const input = $input.first().json;
const body = input.body || input;

const sessionId = body.session_id;
if (!sessionId) throw new Error('session_id is required');

return [{ json: {
  session_id: sessionId,
  idea_id: body.idea_id,
  voice_script_id: body.voice_script_id,
  video_prompt_id: body.video_prompt_id,
  product_image_url: body.product_image_url || '',
  artikul: body.artikul || '',
  show_artikul: body.show_artikul || false,
  a2e_avatar_id: body.a2e_avatar_id || '',
  a2e_voice_id: body.a2e_voice_id || '',
  a2e_background: body.a2e_background || '',
  a2e_resolution: body.a2e_resolution || '1080',
  a2e_anchor_type: parseInt(body.a2e_anchor_type) || 0,
  subtitles_enabled: body.subtitles_enabled != null ? !!body.subtitles_enabled : null,
  music_file_key: body.music_file_key || '',
  music_volume: parseFloat(body.music_volume) || 0.3
}}];

const dbData = $input.first().json;
const params = $('рџ”Ќ Р’Р°Р»РёРґР°С†РёСЏ РІС…РѕРґР°').first().json;

const baseUrl = (dbData.a2e_base_url || 'https://video.a2e.ai').replace(/\/+$/, '');
const avatarId = params.a2e_avatar_id || dbData.default_avatar_id || '';
const voiceId = params.a2e_voice_id || dbData.default_voice_id || '';
const voiceCountry = dbData.voice_country || 'ru';
const voiceRegion = dbData.voice_region || '';
const speechRate = parseFloat(dbData.speech_rate) || 1.0;
const resolution = parseInt(params.a2e_resolution || dbData.default_resolution) || 1080;
const background = params.a2e_background || params.product_image_url || dbData.default_background || '';

// РЎСѓР±С‚РёС‚СЂС‹: webhook > pipeline_sessions > app_settings
const captionsEnabled = params.subtitles_enabled != null
  ? !!params.subtitles_enabled
  : (dbData.db_subtitles_enabled != null
    ? !!dbData.db_subtitles_enabled
    : dbData.captions_enabled === 'true');

// РњСѓР·С‹РєР°
const musicFileKey = params.music_file_key || dbData.db_music_file_key || '';
const musicVolume = params.music_volume != null ? parseFloat(params.music_volume) : (parseFloat(dbData.db_music_volume) || 0.3);

if (!avatarId) throw new Error('A2E avatar_id not set');
if (!voiceId) throw new Error('A2E voice_id not set');

return [{ json: {
  ...params,
  a2e_base_url: baseUrl,
  a2e_avatar_id: avatarId,
  a2e_voice_id: voiceId,
  voice_country: voiceCountry,
  voice_region: voiceRegion,
  speech_rate: speechRate,
  resolution: resolution,
  background: background,
  captions_enabled: captionsEnabled,
  music_file_key: musicFileKey,
  music_volume: musicVolume,
  script_text: dbData.script_text || '',
  timing_marks: dbData.timing_marks || [],
  prompt_text: dbData.prompt_text || '',
  title: dbData.title || '',
  concept: dbData.concept || '',
  visual_description: dbData.visual_description || ''
}}];

const ctx = $('рџ”— РћР±СЉРµРґРёРЅРµРЅРёРµ РґР°РЅРЅС‹С…').first().json;
const balanceResp = $input.first().json;

const coins = balanceResp?.data?.remainingCoins ?? balanceResp?.data ?? null;
if (coins !== null && typeof coins === 'number' && coins < 10) {
  throw new Error('A2E Р±Р°Р»Р°РЅСЃ СЃР»РёС€РєРѕРј РЅРёР·РєРёР№: ' + coins + ' coins. РџРѕРїРѕР»РЅРёС‚Рµ Р°РєРєР°СѓРЅС‚.');
}

return [{ json: { ...ctx, a2e_balance: coins } }];

