const ttsResponse = $input.first().json;
const ctx = $('рџ”— РћР±СЉРµРґРёРЅРµРЅРёРµ РґР°РЅРЅС‹С…').first().json;

if (ttsResponse.code !== 0) {
  throw new Error('A2E TTS failed: ' + (ttsResponse.msg || JSON.stringify(ttsResponse)));
}

const audioUrl = ttsResponse.data;
if (!audioUrl) throw new Error('A2E TTS did not return audio URL');

return [{ json: {
  ...ctx,
  audio_url: audioUrl
}}];

