const ctx = $('рџЋµ РР·РІР»РµС‡СЊ Р°СѓРґРёРѕ URL').first().json;

const result = {
  session_id: ctx.session_id,
  a2e_base_url: ctx.a2e_base_url,
  anchor_id: ctx.a2e_avatar_id,
  anchor_type: ctx.a2e_anchor_type || 0,
  audioSrc: ctx.audio_url,
  resolution: ctx.resolution || 1080,
  isSkipRs: true,
  isCaptionEnabled: ctx.captions_enabled || false,
  msg: ctx.script_text || '',
  bg_color: null,
  back_id: null
};

if (ctx.background) {
  if (ctx.background.startsWith('#')) {
    const hex = ctx.background.replace('#', '');
    const r = parseInt(hex.substring(0,2), 16);
    const g = parseInt(hex.substring(2,4), 16);
    const b = parseInt(hex.substring(4,6), 16);
    result.bg_color = `rgb(${r},${g},${b})`;
  } else {
    result.back_id = ctx.background;
  }
}

// Р”РёР°РіРЅРѕСЃС‚РёРєР°: Р»РѕРіРёСЂСѓРµРј С‡С‚Рѕ РѕС‚РїСЂР°РІР»СЏРµРј
console.log('A2E generate request:', JSON.stringify(result, null, 2));

return [{ json: result }];

const response = $input.first().json;
console.log('A2E video/generate response:', JSON.stringify(response).substring(0, 500));

if (response.code !== undefined && response.code !== 0) {
  throw new Error('A2E code=' + response.code + ': ' + (response.msg || '').substring(0, 200));
}

const videoId = response.data?._id || response._id;
if (!videoId) {
  throw new Error('A2E: РЅРµС‚ _id. code=' + response.code + ' msg=' + (response.msg || 'empty'));
}

return [{ json: {
  video_id: videoId,
  session_id: $('рџЏ—пёЏ A2E Р·Р°РїСЂРѕСЃ').first().json.session_id,
  a2e_base_url: $('рџЏ—пёЏ A2E Р·Р°РїСЂРѕСЃ').first().json.a2e_base_url,
  poll_count: 0
}}];

const prev = $input.first().json;
const statusData = prev.data?.[0] || {};
const status = (statusData.status || 'unknown').toLowerCase();

if (status === 'fail' || status === 'error' || status === 'failed') {
  throw new Error('A2E РіРµРЅРµСЂР°С†РёСЏ РїСЂРѕРІР°Р»РёР»Р°СЃСЊ: ' + JSON.stringify(statusData));
}

const pollCount = (prev.poll_count || 0) + 1;
if (pollCount > 90) {
  throw new Error('A2E timeout: ' + pollCount + ' polls (' + Math.round(pollCount * 20 / 60) + ' min)');
}

return [{ json: {
  video_id: prev.video_id || $('рџ”‘ РР·РІР»РµС‡СЊ video_id').first().json.video_id,
  session_id: prev.session_id || $('рџ”‘ РР·РІР»РµС‡СЊ video_id').first().json.session_id,
  a2e_base_url: prev.a2e_base_url || $('рџ”‘ РР·РІР»РµС‡СЊ video_id').first().json.a2e_base_url,
  poll_count: pollCount
}}];

const response = $input.first().json;
const statusData = response.data?.[0] || {};
const videoUrl = statusData.result;
if (!videoUrl) throw new Error('A2E did not return video URL (result field)');

const sessionId = $('рџ”‘ РР·РІР»РµС‡СЊ video_id').first().json.session_id;

return [{ json: {
  session_id: sessionId,
  raw_video_url: videoUrl,
  a2e_video_id: $('рџ”‘ РР·РІР»РµС‡СЊ video_id').first().json.video_id
}}];

const ctx = $('рџ”— РћР±СЉРµРґРёРЅРµРЅРёРµ РґР°РЅРЅС‹С…').first().json;
const sessionId = ctx.session_id;
const rawVideoUrl = $('рџЋ¬ URL РІРёРґРµРѕ').first().json.raw_video_url;
const musicKey = ctx.music_file_key || '';
const musicVolume = parseFloat(ctx.music_volume) || 0.3;

if (!musicKey) {
  // Р‘РµР· РјСѓР·С‹РєРё вЂ” РёСЃРїРѕР»СЊР·СѓРµРј РѕСЂРёРіРёРЅР°Р»СЊРЅРѕРµ РІРёРґРµРѕ РѕС‚ A2E
  return [{ json: {
    session_id: sessionId,
    raw_video_url: rawVideoUrl,
    final_video_url: rawVideoUrl,
    command: 'echo NO_MUSIC_NEEDED'
  }}];
}

// РЎ РјСѓР·С‹РєРѕР№ вЂ” FFmpeg РјРёРєСЃРёРЅРі
const outputPath = '/home/node/output/a2e_final_' + sessionId + '.mp4';
const workDir = '/tmp/a2e_mix_' + sessionId;

const lines = [
  'set -e',
  'mkdir -p ' + workDir,
  'wget -q --timeout=180 -O ' + workDir + '/video.mp4 "' + rawVideoUrl.replace(/"/g, '\\"') + '"',
  'wget -q --timeout=60 -O ' + workDir + '/music.mp3 "http://minio:9000/content-factory/' + musicKey + '"',
  "ffmpeg -y -i " + workDir + "/video.mp4 -i " + workDir + "/music.mp3 -filter_complex '[0:a]volume=1.0[voice];[1:a]volume=" + musicVolume + "[music];[voice][music]amix=inputs=2:duration=first:dropout_transition=2[aout]' -map 0:v -map '[aout]' -c:v copy -c:a aac -b:a 192k -shortest " + outputPath,
  'rm -rf ' + workDir,
  'echo MUSIC_DONE'
];

return [{ json: {
  session_id: sessionId,
  raw_video_url: rawVideoUrl,
  final_video_url: outputPath,
  command: lines.join('\n')
}}];
